public boolean isSubtype(JSType other) {
  if (!(other instanceof ArrowType)) {
    return false;
  }

  ArrowType that = (ArrowType) other;

  // Return type subtyping (covariant)
  if (!this.returnType.isSubtype(that.returnType)) {
    return false;
  }

  // Ensure number of required this parameters are not more than the other
  int thisRequiredCount = 0;
  int thatRequiredCount = 0;

  Node thisParam = parameters.getFirstChild();
  Node thatParam = that.parameters.getFirstChild();
  while (thisParam != null) {
    if (!thisParam.isOptionalArg()) {
      thisRequiredCount++;
    }
    thisParam = thisParam.getNext();
  }
  while (thatParam != null) {
    if (!thatParam.isOptionalArg()) {
      thatRequiredCount++;
    }
    thatParam = thatParam.getNext();
  }
  if (thisRequiredCount > thatRequiredCount) {
    return false;
  }

  // Reset parameter iteration
  thisParam = parameters.getFirstChild();
  thatParam = that.parameters.getFirstChild();
// Param types subtyping (contravariant)
  while (thisParam != null && thatParam != null) {
    JSType thisParamType = thisParam.getJSType();
    JSType thatParamType = thatParam.getJSType();
    if (thisParamType != null) {
      if (thatParamType == null || !thatParamType.isSubtype(thisParamType)) {
        return false;
      }
    }

    boolean thisIsVarArgs = thisParam.isVarArgs();
    boolean thatIsVarArgs = thatParam.isVarArgs();

    // don't advance if we have variable arguments
    if (!thisIsVarArgs) {
      thisParam = thisParam.getNext();
    }
    if (!thatIsVarArgs) {
      thatParam = thatParam.getNext();
    }

    // both var_args indicates the end
    if (thisIsVarArgs && thatIsVarArgs) {
      thisParam = null;
      thatParam = null;
    }
  }

  return true;
